import {
  queryOptions,
  type UseQueryOptions,
  useQuery,
} from "@tanstack/react-query";
import { ApiError } from "../../client";
import type { ApiClientError } from "../../types";
import { getOrgNextApiClient } from "./client";
import { orgNextAppBootstrapQueryKeys } from "./queryKeys";
import type {
  OrgNextAppBootstrap,
  OrgNextTenant,
  OrgNextTenantMembership,
  OrgNextUser,
} from "./types";
import { ORG_NEXT_APP_BOOTSTRAP_USER_ID } from "./types";

type UseGetAppBootstrapParams = {
  enabled?: boolean;
  performRedirect?: boolean;
  tenantId?: number;
  /** Defaults to {@link ORG_NEXT_APP_BOOTSTRAP_USER_ID}. */
  userId?: number;
};

type UseGetAppBootstrapOptions = Omit<
  UseQueryOptions<
    OrgNextAppBootstrap,
    ApiClientError,
    OrgNextAppBootstrap,
    ReturnType<typeof orgNextAppBootstrapQueryKeys.entity>["queryKey"]
  >,
  "queryFn" | "queryKey"
>;

const isUnauthorized = (error: unknown) =>
  error instanceof ApiError && error.response?.status === 401;

const pickCurrentTenant = (
  accessibleTenants: OrgNextTenant[],
  tenantId?: number,
) => {
  if (tenantId === undefined) {
    return accessibleTenants[0] ?? null;
  }

  return accessibleTenants.find((tenant) => tenant.id === tenantId) ?? null;
};

const buildAppBootstrap = ({
  accessibleTenants,
  membershipsForUser,
  tenantId,
  user,
}: {
  accessibleTenants: OrgNextTenant[];
  membershipsForUser: OrgNextTenantMembership[];
  tenantId?: number;
  user: OrgNextUser;
}): OrgNextAppBootstrap => {
  const currentTenant = pickCurrentTenant(accessibleTenants, tenantId);
  const currentMembership = currentTenant
    ? (membershipsForUser.find(
        (membership) => membership.tenant_id === currentTenant.id,
      ) ?? null)
    : (membershipsForUser[0] ?? null);

  return {
    accessibleTenants,
    currentMembership,
    currentTenant,
    currentUser: user,
    memberships: membershipsForUser,
    tenant: currentTenant,
    tenants: accessibleTenants,
    user,
    users: [user],
  };
};

async function fetchMembershipsForUser(
  client: ReturnType<typeof getOrgNextApiClient>,
  userId: number,
): Promise<OrgNextTenantMembership[]> {
  try {
    return await client.get<OrgNextTenantMembership[]>(
      `/tenant_memberships?user_id=${userId}`,
    );
  } catch (error) {
    if (isUnauthorized(error)) {
      throw error;
    }

    return [];
  }
}

async function fetchTenantsForMemberships(
  client: ReturnType<typeof getOrgNextApiClient>,
  memberships: OrgNextTenantMembership[],
): Promise<OrgNextTenant[]> {
  const tenants: OrgNextTenant[] = [];

  for (const membership of memberships) {
    try {
      const tenant = await client.get<OrgNextTenant>(
        `/tenants/${membership.tenant_id}`,
      );
      tenants.push(tenant);
    } catch (error) {
      if (isUnauthorized(error)) {
        throw error;
      }
    }
  }

  return tenants;
}

export const useGetAppBootstrapQueryOptions = (
  {
    enabled = true,
    performRedirect = false,
    tenantId,
    userId: userIdParam,
  }: UseGetAppBootstrapParams = {},
  options: UseGetAppBootstrapOptions = {},
) => {
  const userId = userIdParam ?? ORG_NEXT_APP_BOOTSTRAP_USER_ID;

  const queryKey = orgNextAppBootstrapQueryKeys.entity({
    namespace: "org",
    parameters: { tenantId, userId },
    resourceId: userId.toString(),
  }).queryKey;

  return queryOptions({
    enabled,
    queryFn: async () => {
      const client = getOrgNextApiClient(performRedirect);

      const user = await client.get<OrgNextUser>(`/users/${userId}`);

      const membershipsForUser = await fetchMembershipsForUser(client, userId);
      const accessibleTenants = await fetchTenantsForMemberships(
        client,
        membershipsForUser,
      );

      return buildAppBootstrap({
        accessibleTenants,
        membershipsForUser,
        tenantId,
        user,
      });
    },
    queryKey,
    staleTime: 60000,
    ...options,
  });
};

export const useGetAppBootstrap = (
  params: UseGetAppBootstrapParams = {},
  options: UseGetAppBootstrapOptions = {},
) => {
  return useQuery(useGetAppBootstrapQueryOptions(params, options));
};

